export const LANDMARK_EVENTS = [
  { question: "Where is the Eiffel Tower?", answer: "Paris, France", lat: 48.8584, lng: 2.2945, info: "Gustave Eiffel's 330-metre iron lattice tower was built for the 1889 World's Fair and remained the world's tallest man-made structure for 41 years. Today it receives around 7 million visitors annually, making it the most visited paid monument on Earth.", category: "landmarks" },
  { question: "Where is the Burj Khalifa?", answer: "Dubai, UAE", lat: 25.1972, lng: 55.2744, info: "Standing 828 metres tall with 163 floors, the Burj Khalifa has been the world's tallest building since its completion in 2010. It contains residences, offices, a hotel, and observation decks visible from over 95 kilometres away.", category: "landmarks" },
  { question: "Where is the Empire State Building?", answer: "New York City, USA", lat: 40.7484, lng: -73.9857, info: "Completed in 1931 in just 410 days, the 443-metre Art Deco skyscraper held the title of world's tallest building for nearly 40 years. It was struck by a B-25 bomber in 1945 and remains one of America's most recognisable landmarks.", category: "landmarks" },
  { question: "Where is Big Ben?", answer: "London, UK", lat: 51.5007, lng: -0.1246, info: "The Elizabeth Tower at the Palace of Westminster houses the 13.5-tonne Great Bell, nicknamed Big Ben, which has chimed on the hour since 1859. The tower was renamed in honour of Queen Elizabeth II during her Diamond Jubilee in 2012.", category: "landmarks" },
  { question: "Where is Taipei 101?", answer: "Taipei, Taiwan", lat: 25.0330, lng: 121.5654, info: "This 508-metre skyscraper was the world's tallest building from 2004 to 2010 and was the first to break the half-kilometre barrier. Its design is inspired by bamboo segments and traditional pagoda architecture, and it contains a massive 660-tonne tuned mass damper to reduce sway.", category: "landmarks" },
  { question: "Where is the Willis Tower?", answer: "Chicago, USA", lat: 41.8789, lng: -87.6359, info: "Formerly known as the Sears Tower, this 442-metre building held the title of world's tallest from 1973 to 1998. Its glass-floored Skydeck observation boxes extend 1.3 metres beyond the building's edge on the 103rd floor.", category: "landmarks" },
  { question: "Where is the Space Needle?", answer: "Seattle, USA", lat: 47.6205, lng: -122.3493, info: "Built for the 1962 World's Fair, the Space Needle stands 184 metres tall and was designed to withstand winds of 320 km/h and earthquakes of up to 9.1 magnitude. Its revolving restaurant completes a full rotation every 47 minutes.", category: "landmarks" },
  { question: "Where is the CN Tower?", answer: "Toronto, Canada", lat: 43.6426, lng: -79.3871, info: "Standing 553 metres tall, the CN Tower was the world's tallest free-standing structure from 1976 to 2007. It serves as a key telecommunications hub and its EdgeWalk attraction lets visitors walk on the outside ledge 356 metres above the ground.", category: "landmarks" },
  { question: "Where are the Petronas Towers?", answer: "Kuala Lumpur, Malaysia", lat: 3.1579, lng: 101.7116, info: "These twin supertall skyscrapers stand 452 metres tall and were the world's tallest buildings from 1998 to 2004. Connected by a sky bridge on the 41st and 42nd floors, they were designed by Cesar Pelli and draw on Islamic geometric patterns.", category: "landmarks" },
  { question: "Where is the Chrysler Building?", answer: "New York City, USA", lat: 40.7516, lng: -73.9755, info: "Completed in 1930, this 319-metre Art Deco masterpiece features a stainless steel eagle gargoyle crown and was briefly the world's tallest building for just 11 months before the Empire State Building surpassed it. It remains one of the finest examples of Art Deco architecture anywhere.", category: "landmarks" },
  { question: "Where is the Flatiron Building?", answer: "New York City, USA", lat: 40.7411, lng: -73.9897, info: "Built in 1902, the Flatiron Building is a 22-storey triangular skyscraper that occupies a triangular block at the intersection of Broadway and Fifth Avenue. It was one of New York's first true skyscrapers and its unusual wedge shape made it an instant icon.", category: "landmarks" },
  { question: "Where is One World Trade Center?", answer: "New York City, USA", lat: 40.7127, lng: -74.0134, info: "Rising 541 metres, One World Trade Center is the tallest building in the Western Hemisphere, completed in 2014 on the site adjacent to the September 11 memorial pools. Its height was deliberately designed to match the symbolic figure of 1,776 feet, the year of American independence.", category: "landmarks" },
  { question: "Where is the Palace of Versailles?", answer: "Versailles, France", lat: 48.8049, lng: 2.1204, info: "Originally a hunting lodge, Louis XIV transformed Versailles into the grandest royal palace in the world, housing the French court from 1682 until the Revolution in 1789. Its Hall of Mirrors stretches 73 metres and was the setting for the signing of the Treaty of Versailles in 1919.", category: "landmarks" },
  { question: "Where is Buckingham Palace?", answer: "London, UK", lat: 51.5014, lng: -0.1419, info: "The official London residence of the British monarch since Queen Victoria moved in 1837, Buckingham Palace has 775 rooms including 19 state rooms and 78 bathrooms. The Changing of the Guard ceremony outside its gates is one of London's most popular tourist attractions.", category: "landmarks" },
  { question: "Where is Neuschwanstein Castle?", answer: "Bavaria, Germany", lat: 47.5576, lng: 10.7498, info: "Commissioned by the reclusive King Ludwig II of Bavaria in 1869, Neuschwanstein's fairy-tale turrets and Alpine setting inspired Walt Disney's Sleeping Beauty Castle. Ludwig lived in it for only 172 days before his mysterious death in 1886.", category: "landmarks" },
  { question: "Where is the Alhambra?", answer: "Granada, Spain", lat: 37.1760, lng: -3.5881, info: "This magnificent Moorish palace and fortress complex was the last stronghold of the Nasrid dynasty in Spain, completed in the 14th century with breathtaking geometric tilework, arabesques, and reflecting pools. The Reconquista ended here in 1492 when Ferdinand and Isabella accepted Granada's surrender.", category: "landmarks" },
  { question: "Where is Topkapi Palace?", answer: "Istanbul, Turkey", lat: 41.0115, lng: 28.9833, info: "Topkapi served as the administrative centre of the Ottoman Empire for nearly 400 years, housing up to 4,000 people at its peak including the sultan's harem and treasury. It contains some of Islam's holiest relics, including the mantle and sword of the Prophet Muhammad.", category: "landmarks" },
  { question: "Where is the Potala Palace?", answer: "Lhasa, Tibet, China", lat: 29.6575, lng: 91.1175, info: "Perched atop Marpo Ri hill at 3,700 metres altitude, the Potala Palace was the winter residence of the Dalai Lamas from 1649 and contains over 1,000 rooms with thousands of shrines and precious artworks. It is divided into the White Palace for administrative use and the Red Palace for religious ceremonies.", category: "landmarks" },
  { question: "Where is the Forbidden City?", answer: "Beijing, China", lat: 39.9163, lng: 116.3972, info: "The world's largest palace complex served as the imperial home of 24 emperors of the Ming and Qing dynasties for nearly 500 years. Covering 72 hectares with 980 surviving buildings, it was off-limits to commoners for centuries and is now known as the Palace Museum.", category: "landmarks" },
  { question: "Where is Edinburgh Castle?", answer: "Edinburgh, Scotland", lat: 55.9486, lng: -3.2008, info: "Dominating the skyline from its volcanic rock, Edinburgh Castle has been a royal fortress since at least the 12th century and houses the Scottish Crown Jewels and the Stone of Destiny. The One O'Clock Gun has been fired here every weekday since 1861 to allow ships in the Firth of Forth to set their chronometers.", category: "landmarks" },
  { question: "Where is Prague Castle?", answer: "Prague, Czech Republic", lat: 50.0909, lng: 14.4019, info: "The largest ancient castle complex in the world stretches over 70,000 square metres and contains palaces, churches, galleries, and gardens spanning over a thousand years of architectural history. It has been the seat of Czech rulers and presidents since the 9th century.", category: "landmarks" },
  { question: "Where is Hagia Sophia?", answer: "Istanbul, Turkey", lat: 41.0086, lng: 28.9802, info: "Built by Emperor Justinian I and completed in 537 AD, Hagia Sophia was the world's largest cathedral for nearly a thousand years. Converted to a mosque after the Ottoman conquest in 1453, then a museum in 1934, it was reconverted to a mosque in 2020.", category: "landmarks" },
  { question: "Where is St Peter's Basilica?", answer: "Vatican City", lat: 41.9022, lng: 12.4539, info: "The world's largest church by interior volume, St Peter's Basilica was rebuilt during the Renaissance over the tomb of Saint Peter the Apostle, with Michelangelo designing the iconic 136-metre dome. It can hold up to 60,000 worshippers and is the ceremonial centre of the Catholic Church.", category: "landmarks" },
  { question: "Where is the Sagrada Família?", answer: "Barcelona, Spain", lat: 41.4036, lng: 2.1744, info: "Antoni Gaudí's unfinished basilica has been under construction since 1882 and is expected to be completed around 2026, making it the longest-running construction project in the world. Its forest-like interior and organic stone facades represent Gaudí's synthesis of Gothic and Art Nouveau architecture.", category: "landmarks" },
  { question: "Where is the Dome of the Rock?", answer: "Jerusalem", lat: 31.7781, lng: 35.2354, info: "Completed in 691 AD, the Dome of the Rock is the oldest surviving Islamic monument and stands on the Temple Mount, Judaism's holiest site. The gold dome covers a sacred rock believed by Muslims to be where Muhammad ascended to heaven and by Jews to be the Foundation Stone of creation.", category: "landmarks" },
  { question: "Where is the Western Wall?", answer: "Jerusalem", lat: 31.7767, lng: 35.2345, info: "The Western Wall is a remnant of the retaining wall of the Second Temple Mount, destroyed by the Romans in 70 AD, and is Judaism's holiest accessible prayer site. Millions of visitors each year insert small paper notes with prayers into its ancient stone cracks.", category: "landmarks" },
  { question: "Where is the Blue Mosque?", answer: "Istanbul, Turkey", lat: 41.0054, lng: 28.9768, info: "Built between 1609 and 1616 under Sultan Ahmed I, the Sultan Ahmed Mosque is nicknamed the Blue Mosque for its 20,000 handmade Iznik blue ceramic tiles covering the interior walls. It is the only mosque in Istanbul with six minarets, which caused a controversy at the time of its construction.", category: "landmarks" },
  { question: "Where is the Sistine Chapel?", answer: "Vatican City", lat: 41.9029, lng: 12.4545, info: "Pope Julius II commissioned Michelangelo to paint the Sistine Chapel ceiling between 1508 and 1512, producing one of the world's greatest artistic masterpieces including the iconic Creation of Adam scene. The chapel also houses the conclave in which new popes are elected.", category: "landmarks" },
  { question: "Where is Notre-Dame Cathedral?", answer: "Paris, France", lat: 48.8530, lng: 2.3499, info: "Construction of this Gothic masterpiece began in 1163 and was completed around 1345, featuring flying buttresses, gargoyles, and stunning rose windows. A devastating fire in April 2019 destroyed the spire and much of the roof, but restoration efforts are underway for a 2024 reopening.", category: "landmarks" },
  { question: "Where is Westminster Abbey?", answer: "London, UK", lat: 51.4994, lng: -0.1273, info: "Westminster Abbey has been the coronation church of English and British monarchs since 1066 and contains the tombs of 17 monarchs along with memorials to many of Britain's greatest figures in Poets' Corner. Every English and British monarch since William the Conqueror has been crowned here except Edward V and Edward VIII.", category: "landmarks" },
  { question: "Where is Chartres Cathedral?", answer: "Chartres, France", lat: 48.4475, lng: 1.4877, info: "Considered the finest example of French High Gothic architecture, Chartres Cathedral was largely built between 1194 and 1220 and retains most of its original 12th and 13th century stained glass. Its 172 windows covering 2,600 square metres of glass are considered the greatest collection of medieval stained glass in the world.", category: "landmarks" },
  { question: "Where is Cologne Cathedral?", answer: "Cologne, Germany", lat: 50.9413, lng: 6.9583, info: "Construction of this Gothic cathedral began in 1248 and was not completed until 1880, making it one of the longest construction projects in history at 632 years. Standing 157 metres tall, it was the world's tallest building from 1880 to 1884 and houses the Shrine of the Three Kings.", category: "landmarks" },
  { question: "Where is St Basil's Cathedral?", answer: "Moscow, Russia", lat: 55.7525, lng: 37.6231, info: "Ivan the Terrible commissioned this riot of colourful onion domes on Red Square to commemorate his capture of Kazan in 1552, completed in 1561. Legend claims Ivan blinded the architects so they could never create anything more beautiful, though historians consider this unlikely.", category: "landmarks" },
  { question: "Where is Borobudur?", answer: "Java, Indonesia", lat: -7.6079, lng: 110.2038, info: "Built in the 9th century during the Sailendra dynasty, Borobudur is the world's largest Buddhist temple and the greatest monument of Buddhism outside India. Its three-tiered mandala structure contains 2,672 relief panels and 504 Buddha statues, and was hidden under volcanic ash for centuries before rediscovery in 1814.", category: "landmarks" },
  { question: "Where is the Shwedagon Pagoda?", answer: "Yangon, Myanmar", lat: 16.7985, lng: 96.1497, info: "At 98 metres tall and plated with gold, the Shwedagon Pagoda is Myanmar's most sacred Buddhist site and is believed to enshrine hairs of the Gautama Buddha along with relics of three previous Buddhas. The stupa's finial is set with 4,531 diamonds, including a 76-carat diamond at the very top.", category: "landmarks" },
  { question: "Where is the Colosseum?", answer: "Rome, Italy", lat: 41.8902, lng: 12.4922, info: "The largest amphitheatre ever built, the Colosseum was completed in 80 AD and could hold between 50,000 and 80,000 spectators for gladiatorial contests, animal hunts, and public executions. An estimated 400,000 people and over a million animals died within its walls over the centuries.", category: "landmarks" },
  { question: "Where is the Parthenon?", answer: "Athens, Greece", lat: 37.9715, lng: 23.7267, info: "Built between 447 and 432 BC as the centrepiece of the Acropolis of Athens, the Parthenon is a Doric temple dedicated to the goddess Athena and represents the pinnacle of Classical Greek architecture. Much of the original marble frieze was controversially removed by Lord Elgin and is now held in the British Museum.", category: "landmarks" },
  { question: "Where is Machu Picchu?", answer: "Cusco Region, Peru", lat: -13.1631, lng: -72.5450, info: "Built by the Inca emperor Pachacuti around 1450 AD at 2,430 metres above sea level, Machu Picchu was abandoned roughly a century later and remained unknown to the outside world until Hiram Bingham's 1911 expedition. Its precisely fitted dry-stone walls and astronomical alignments continue to astonish archaeologists.", category: "landmarks" },
  { question: "Where is Angkor Wat?", answer: "Siem Reap, Cambodia", lat: 13.4125, lng: 103.8670, info: "Built by Khmer king Suryavarman II in the early 12th century, Angkor Wat is the world's largest religious monument, covering over 160 hectares. Originally a Hindu temple dedicated to Vishnu, it was gradually converted to Buddhism and remains a functioning place of worship today.", category: "landmarks" },
  { question: "Where is Stonehenge?", answer: "Wiltshire, England", lat: 51.1789, lng: -1.8262, info: "This prehistoric stone circle on Salisbury Plain was constructed in phases from around 3000 to 1500 BC, with the massive sarsen stones weighing up to 25 tonnes transported from Marlborough Downs 25 kilometres away. Its precise alignment with the summer solstice sunrise suggests it served as an astronomical calendar.", category: "landmarks" },
  { question: "Where is Petra?", answer: "Ma'an Governorate, Jordan", lat: 30.3285, lng: 35.4444, info: "The ancient Nabataean capital carved into rose-red sandstone cliffs flourished as a trading hub from around the 4th century BC and was home to up to 30,000 people at its peak. The iconic Treasury facade, actually a tomb, rises 43 metres and was carved entirely by hand without scaffolding.", category: "landmarks" },
  { question: "Where is Chichen Itza?", answer: "Yucatán, Mexico", lat: 20.6843, lng: -88.5678, info: "One of the largest and best-preserved Maya cities, Chichen Itza flourished between the 9th and 12th centuries AD and was a major regional political and ceremonial centre. The El Castillo pyramid is designed so that during the spring and autumn equinoxes, sunlight creates the illusion of a serpent descending its staircase.", category: "landmarks" },
  { question: "Where are the ruins of Pompeii?", answer: "Campania, Italy", lat: 40.7508, lng: 14.4868, info: "The Roman city of Pompeii was buried under 4 to 6 metres of volcanic ash and pumice when Mount Vesuvius erupted catastrophically in 79 AD, preserving it remarkably intact for nearly 1,700 years. Excavations begun in the 18th century have revealed an extraordinary snapshot of Roman daily life, including bakeries, brothels, and homes with their furniture still in place.", category: "landmarks" },
  { question: "Where is the Roman Forum?", answer: "Rome, Italy", lat: 41.8925, lng: 12.4853, info: "The Roman Forum was the centre of political, religious, and commercial life in ancient Rome for over a thousand years, surrounded by the ruins of important government buildings. Julius Caesar was cremated here after his assassination in 44 BC, and today it remains one of the most visited archaeological sites in the world.", category: "landmarks" },
  { question: "Where is the Pantheon?", answer: "Rome, Italy", lat: 41.8986, lng: 12.4769, info: "The best-preserved ancient Roman building, the Pantheon was completed around 125 AD during Hadrian's reign and has been in continuous use ever since — serving as a church since 609 AD. Its unreinforced concrete dome with an oculus at the crown was the world's largest for 1,300 years until Brunelleschi's Florence Cathedral dome.", category: "landmarks" },
  { question: "Where is Abu Simbel?", answer: "Aswan Governorate, Egypt", lat: 22.3372, lng: 31.6258, info: "Ramesses II carved these two colossal rock temples from a mountainside around 1264 BC, with four 20-metre seated statues of himself guarding the entrance. In the 1960s the entire complex was physically cut into blocks and relocated 65 metres uphill to save it from rising Lake Nasser waters — one of history's greatest engineering feats.", category: "landmarks" },
  { question: "Where is Karnak Temple?", answer: "Luxor, Egypt", lat: 25.7188, lng: 32.6573, info: "The Karnak Temple Complex is the largest religious building ever constructed, covering over 100 hectares and representing the accumulated building efforts of more than 30 pharaohs over 2,000 years. Its hypostyle hall contains 134 massive sandstone columns, the tallest standing 24 metres high.", category: "landmarks" },
  { question: "Where is the Great Sphinx?", answer: "Giza, Egypt", lat: 29.9753, lng: 31.1376, info: "Carved from a single limestone outcrop, the Great Sphinx stands 20 metres tall and 73 metres long, making it the world's largest monolithic statue. Believed to depict Pharaoh Khafre, it was carved around 2500 BC and its missing nose is thought to have been destroyed during the Mamluk period.", category: "landmarks" },
  { question: "Where is Persepolis?", answer: "Fars Province, Iran", lat: 29.9350, lng: 52.8911, info: "Founded around 518 BC by Darius the Great, Persepolis served as the ceremonial capital of the Achaemenid Persian Empire and was used for Nowruz (New Year) celebrations. Alexander the Great destroyed it by fire in 330 BC, but its monumental staircases, relief carvings, and Gateway of All Nations survive as testimony to ancient Persian grandeur.", category: "landmarks" },
  { question: "Where is Tikal?", answer: "Petén Department, Guatemala", lat: 17.2220, lng: -89.6237, info: "One of the largest Maya cities, Tikal's temples rise above the jungle canopy of northern Guatemala and were inhabited from around 600 BC to 900 AD at its peak population of around 100,000. Temple IV stands 70 metres tall and was used as a filming location for the Rebel Alliance base in Star Wars: A New Hope.", category: "landmarks" },
  { question: "Where is Teotihuacan?", answer: "State of Mexico, Mexico", lat: 19.6925, lng: -98.8438, info: "At its peak around 450 AD, Teotihuacan was one of the largest cities in the ancient world with perhaps 125,000 inhabitants, yet its builders remain a mystery as no writing system has been found. The Pyramid of the Sun is the third-largest pyramid in the world by volume, rising 65 metres above the Avenue of the Dead.", category: "landmarks" },
  { question: "Where is Göbekli Tepe?", answer: "Şanlıurfa Province, Turkey", lat: 37.2231, lng: 38.9225, info: "Constructed around 9600–8200 BC, Göbekli Tepe is the world's oldest known monumental architecture, predating Stonehenge by 6,000 years and the invention of writing by 5,000 years. Its T-shaped limestone pillars weighing up to 20 tonnes, carved with animals and abstract symbols, have completely overturned theories about the origins of civilisation.", category: "landmarks" },
  { question: "Where is Nan Madol?", answer: "Pohnpei, Micronesia", lat: 6.8447, lng: 158.3321, info: "Built on a coral reef between the 8th and 17th centuries, Nan Madol is a series of 92 artificial islets connected by canals, often called the Venice of the Pacific. Its basalt log walls, some weighing 50 tonnes, were transported by unknown means and the site served as the ceremonial and political seat of the Saudeleur dynasty.", category: "landmarks" },
  { question: "Where are the rock-hewn churches of Lalibela?", answer: "Amhara Region, Ethiopia", lat: 12.0319, lng: 39.0473, info: "Carved entirely from solid red volcanic rock in the 12th–13th centuries during the reign of King Lalibela, these 11 monolithic churches are still active places of worship and pilgrimage for Ethiopian Orthodox Christians. The largest, Bete Medhane Alem, is believed to be the world's largest monolithic church.", category: "landmarks" },
  { question: "Where are the Bagan temples?", answer: "Mandalay Region, Myanmar", lat: 21.1717, lng: 94.8585, info: "During the Pagan Empire's peak from the 9th to 13th centuries, over 10,000 Buddhist temples, pagodas, and monasteries were built in Bagan, of which more than 2,000 survive today. The plain stretching along the Irrawaddy River creates one of the most spectacular archaeological landscapes in Southeast Asia.", category: "landmarks" },
  { question: "Where is Sigiriya?", answer: "Central Province, Sri Lanka", lat: 7.9570, lng: 80.7603, info: "The 5th century AD fortress-palace of King Kashyapa was built atop a 200-metre volcanic rock plug, accessible only via steep staircases and a lion-paw entrance gateway. The site includes remarkably preserved frescoes of celestial maidens painted on the rock face and a sophisticated hydraulic system of gardens and pools at the summit.", category: "landmarks" },
  { question: "Where is the Statue of Liberty?", answer: "New York City, USA", lat: 40.6892, lng: -74.0445, info: "A gift from France to the United States, Frédéric Auguste Bartholdi's 93-metre copper statue was dedicated in 1886 and welcomed millions of immigrants arriving by sea. The torch-bearing figure stands on a star-shaped base and was engineered by Gustave Eiffel, who would later build his eponymous tower.", category: "landmarks" },
  { question: "Where is Christ the Redeemer?", answer: "Rio de Janeiro, Brazil", lat: -22.9519, lng: -43.2105, info: "Standing 38 metres tall atop the 710-metre Corcovado mountain, this Art Deco statue of Jesus Christ was constructed between 1922 and 1931 and is the largest Art Deco statue in the world. Its outstretched arms span 28 metres and it overlooks the entire city of Rio de Janeiro.", category: "landmarks" },
  { question: "Where are the Moai statues?", answer: "Easter Island, Chile", lat: -27.1127, lng: -109.3497, info: "The Rapa Nui people carved approximately 1,000 of these monolithic human figures between the 13th and 16th centuries from compressed volcanic ash called tuff. The tallest erected moai stands nearly 10 metres and weighs 82 tonnes; most face inland to watch over their communities rather than out to sea.", category: "landmarks" },
  { question: "Where is Mount Rushmore?", answer: "South Dakota, USA", lat: 43.8791, lng: -103.4591, info: "Sculptor Gutzon Borglum and 400 workers blasted and carved the 18-metre faces of Washington, Jefferson, Roosevelt, and Lincoln into the Black Hills granite between 1927 and 1941. The memorial was created in the sacred Lakota Sioux territory called the Six Grandfathers, renamed after a New York lawyer who visited the area.", category: "landmarks" },
  { question: "Where is the Lincoln Memorial?", answer: "Washington D.C., USA", lat: 38.8893, lng: -77.0502, info: "Dedicated in 1922, this neoclassical marble memorial houses a 5.8-metre seated marble statue of the 16th president and is inscribed with his Gettysburg Address and Second Inaugural Address. Martin Luther King Jr. delivered his famous 'I Have a Dream' speech on its steps to 250,000 people in August 1963.", category: "landmarks" },
  { question: "Where is the Brandenburg Gate?", answer: "Berlin, Germany", lat: 52.5163, lng: 13.3777, info: "Built between 1788 and 1791 by Prussian King Frederick William II, this neoclassical sandstone gate was for decades a symbol of Germany's division during the Cold War, standing in the no-man's-land between East and West Berlin. It became the backdrop for Ronald Reagan's 1987 'Tear down this wall' speech and is now a symbol of German reunification.", category: "landmarks" },
  { question: "Where is the Arc de Triomphe?", answer: "Paris, France", lat: 48.8738, lng: 2.2950, info: "Commissioned by Napoleon Bonaparte in 1806 to honour the French army, the 50-metre Arc de Triomphe stands at the western end of the Champs-Élysées and has 12 avenues radiating from it. The Tomb of the Unknown Soldier with its eternal flame has burned beneath it since 1921.", category: "landmarks" },
  { question: "Where is Nelson's Column?", answer: "London, UK", lat: 51.5080, lng: -0.1281, info: "Erected in Trafalgar Square between 1840 and 1843 to commemorate Admiral Horatio Nelson's victory and death at the Battle of Trafalgar in 1805, the column stands 51.6 metres tall and is topped by a 5.5-metre sandstone statue of Nelson. Four bronze lions designed by Edwin Landseer were added to its base in 1867.", category: "landmarks" },
  { question: "Where is the Golden Gate Bridge?", answer: "San Francisco, USA", lat: 37.8199, lng: -122.4783, info: "Completed in 1937 after four years of construction, the Golden Gate Bridge spans 2.7 kilometres across the strait connecting San Francisco Bay to the Pacific Ocean and was the world's longest suspension bridge at the time. Its signature International Orange paint was chosen to make it visible in the Bay's frequent fog.", category: "landmarks" },
  { question: "Where is Tower Bridge?", answer: "London, UK", lat: 51.5055, lng: -0.0754, info: "Completed in 1894, Tower Bridge is a combined bascule and suspension bridge that can be raised to allow tall ships to pass — it opens around 800 times a year. Despite its medieval Gothic appearance, the bridge was a cutting-edge Victorian engineering achievement using steel frames clad in Cornish granite and Portland stone.", category: "landmarks" },
  { question: "Where is Sydney Harbour Bridge?", answer: "Sydney, Australia", lat: -33.8523, lng: 151.2108, info: "The world's largest steel arch bridge, completed in 1932 after eight years of construction that employed 1,400 workers, with 16 dying during construction. Affectionately nicknamed 'The Coathanger' by locals, it carries eight lanes of road traffic, two railway lines, a footpath, and a cycleway across Sydney Harbour.", category: "landmarks" },
  { question: "Where is Charles Bridge?", answer: "Prague, Czech Republic", lat: 50.0865, lng: 14.4114, info: "Built between 1357 and the early 15th century on the orders of King Charles IV, this 516-metre Gothic stone bridge crosses the Vltava River and is lined with 30 baroque statues of saints added between 1683 and 1714. The bridge was the only crossing over the Vltava for four centuries and was a key trade route.", category: "landmarks" },
  { question: "Where is the Millau Viaduct?", answer: "Aveyron, France", lat: 44.0792, lng: 3.0158, info: "Designed by Norman Foster and completed in 2004, the Millau Viaduct is the world's tallest bridge, with one mast reaching 343 metres — taller than the Eiffel Tower. It spans the Tarn River valley in southern France and carries the A75 motorway, cutting a 3-hour journey via Millau town to mere minutes.", category: "landmarks" },
  { question: "Where is the Rialto Bridge?", answer: "Venice, Italy", lat: 45.4380, lng: 12.3358, info: "The oldest and most famous of the four bridges spanning Venice's Grand Canal, the Rialto Bridge was completed in 1591 after a design competition that Michelangelo and Palladio both entered. Its single arch spans 28 metres and the bridge is lined with shops on both sides, a tradition going back to its medieval wooden predecessor.", category: "landmarks" },
  { question: "Where is the Louvre?", answer: "Paris, France", lat: 48.8606, lng: 2.3376, info: "The world's largest and most visited art museum received 9.6 million visitors in 2019 and houses 35,000 works on permanent display including the Mona Lisa and the Venus de Milo. The medieval fortress became a royal palace in the 16th century and was converted to a public museum during the French Revolution in 1793.", category: "landmarks" },
  { question: "Where is the British Museum?", answer: "London, UK", lat: 51.5194, lng: -0.1270, info: "Founded in 1753 as the world's first public national museum, the British Museum holds around 8 million objects spanning two million years of human history, with permanent displays of Egyptian mummies, the Rosetta Stone, and the Elgin Marbles. Its Great Court, enclosed by a steel and glass roof designed by Norman Foster, is Europe's largest covered public square.", category: "landmarks" },
  { question: "Where is the Hermitage Museum?", answer: "St Petersburg, Russia", lat: 59.9398, lng: 30.3146, info: "Founded by Catherine the Great in 1764, the Hermitage is one of the world's largest and oldest museums, housed primarily in the Winter Palace and containing over 3 million items including works by Leonardo, Rembrandt, and Michelangelo. Its 1,786 doors, 1,945 windows, and 1,057 rooms would take 11 years to view at one minute per exhibit.", category: "landmarks" },
  { question: "Where is the Rijksmuseum?", answer: "Amsterdam, Netherlands", lat: 52.3600, lng: 4.8852, info: "The Netherlands' national museum of art and history was founded in 1800 and occupies a magnificent Neo-Gothic and Neo-Renaissance building opened in 1885. Its highlights include Rembrandt's The Night Watch (3.6 by 4.4 metres, the largest Dutch Golden Age painting) and Vermeer's The Milkmaid.", category: "landmarks" },
  { question: "Where is the Guggenheim Museum Bilbao?", answer: "Bilbao, Spain", lat: 43.2688, lng: -2.9340, info: "Frank Gehry's titanium-clad deconstructivist masterpiece opened in 1997 and is credited with triggering the 'Bilbao Effect' — the idea that a single landmark building can transform a city's economy and image. The museum's twisting, shimmering forms contain 24 galleries across 11,000 square metres.", category: "landmarks" },
  { question: "Where is the Smithsonian Institution?", answer: "Washington D.C., USA", lat: 38.8888, lng: -77.0261, info: "The world's largest museum and research complex comprises 19 museums, 21 libraries, and 9 research centres, all free to enter and mostly concentrated along the National Mall. Founded in 1846 using a bequest from British scientist James Smithson, who had never visited America, it holds 155 million artefacts and specimens.", category: "landmarks" },
  { question: "Where are the Vatican Museums?", answer: "Vatican City", lat: 41.9065, lng: 12.4536, info: "Founded by Pope Julius II in the early 16th century, the Vatican Museums contain one of the world's greatest art collections built up by popes over centuries, including Greek and Roman sculptures, Renaissance paintings, and the Raphael Rooms. The 7-kilometre route through the museums ends in the Sistine Chapel.", category: "landmarks" },
  { question: "Where is the Great Wall of China?", answer: "Northern China", lat: 40.4319, lng: 116.5704, info: "Built over many centuries from as early as the 7th century BC and largely constructed during the Ming dynasty (1368–1644), the Great Wall stretches over 21,000 kilometres and involved the labour of millions of soldiers, peasants, and prisoners. Despite popular belief, it cannot be seen from space with the naked eye.", category: "landmarks" },
  { question: "Where is the Anne Frank House?", answer: "Amsterdam, Netherlands", lat: 52.3752, lng: 4.8840, info: "Anne Frank hid with her family in a concealed apartment above a warehouse on the Prinsengracht canal for over two years from July 1942, writing her famous diary before being betrayed and sent to Bergen-Belsen concentration camp. The house became a museum in 1960 and receives over a million visitors annually.", category: "landmarks" },
  { question: "Where is Alcatraz Island?", answer: "San Francisco Bay, USA", lat: 37.8267, lng: -122.4230, info: "The island in San Francisco Bay housed a maximum-security federal penitentiary from 1934 to 1963, holding famous criminals including Al Capone and Robert Stroud (the Birdman of Alcatraz). The strong tidal currents and cold water around the island were considered sufficient deterrent against escape, though 36 prisoners attempted it.", category: "landmarks" },
  { question: "Where is Auschwitz-Birkenau?", answer: "Oświęcim, Poland", lat: 50.0341, lng: 19.1782, info: "The largest of the Nazi concentration and extermination camps operated from 1940 to 1945, where approximately 1.1 million people — the vast majority of them Jewish — were murdered. The site is preserved as a UNESCO World Heritage Site and museum, with the words 'Arbeit Macht Frei' ('Work sets you free') still reading above the gate.", category: "landmarks" },
  { question: "Where is the Taj Mahal?", answer: "Agra, India", lat: 27.1751, lng: 78.0421, info: "Mughal emperor Shah Jahan built this white marble mausoleum for his beloved wife Mumtaz Mahal, who died in 1631, employing 20,000 artisans for over 20 years. The perfect symmetry, intricate pietra dura inlay work, and reflective pool create one of the world's most recognised and romantic architectural achievements.", category: "landmarks" },
  { question: "Where is the Kremlin?", answer: "Moscow, Russia", lat: 55.7520, lng: 37.6175, info: "Moscow's Kremlin is a fortified complex at the heart of the Russian capital and has served as the official residence of the Russian president since 1991, following centuries as the seat of tsars and Soviet leaders. Its triangular red-brick walls enclose five palaces, four cathedrals, and the world's largest bell and cannon.", category: "landmarks" },
  { question: "Where is the Trevi Fountain?", answer: "Rome, Italy", lat: 41.9009, lng: 12.4833, info: "The largest Baroque fountain in Rome, completed in 1762 by Nicola Salvi, marks the terminal point of one of Rome's ancient aqueducts, the Acqua Vergine. The tradition of throwing a coin into the fountain to ensure a return to Rome generates around €1.5 million per year, donated to the city's food bank.", category: "landmarks" },
  { question: "Where is the Leaning Tower of Pisa?", answer: "Pisa, Italy", lat: 43.7230, lng: 10.3966, info: "Construction of this freestanding bell tower began in 1173 and took nearly 200 years to complete, with its famous lean developing during construction due to soft subsoil on one side. Stabilisation work between 1990 and 2001 reduced the lean from 5.5 to 3.97 degrees and is expected to keep it stable for at least another 200 years.", category: "landmarks" },
  { question: "Where is Mont Saint-Michel?", answer: "Normandy, France", lat: 48.6361, lng: -1.5115, info: "This tidal island commune with its iconic Benedictine abbey is accessible by a causeway that becomes submerged during high tides, which rise up to 14 metres — among the highest in Europe. The abbey was founded in 966 and the island was used as a prison during the French Revolution and 19th century.", category: "landmarks" },
  { question: "Where is Carcassonne?", answer: "Aude, France", lat: 43.2119, lng: 2.3522, info: "The medieval fortified city of Carcassonne is Europe's largest surviving walled city, with a double ring of ramparts and 52 towers stretching nearly 3 kilometres. Though in a dilapidated state by the 19th century, architect Eugène Viollet-le-Duc oversaw an extensive restoration from 1853 that is itself now controversial for its romantic embellishments.", category: "landmarks" },
  { question: "Where is the Cliffs of Moher?", answer: "County Clare, Ireland", lat: 52.9720, lng: -9.4264, info: "Rising up to 214 metres above the Atlantic Ocean and stretching 14 kilometres along the coast of County Clare, the Cliffs of Moher are Ireland's most visited natural attraction with over 1.5 million visitors annually. On clear days, the Aran Islands, Galway Bay, and the mountains of Connemara are visible from the clifftops.", category: "landmarks" },
  { question: "Where is the Acropolis of Athens?", answer: "Athens, Greece", lat: 37.9715, lng: 23.7267, info: "The ancient citadel sitting 156 metres above Athens contains several significant ancient buildings, most importantly the Parthenon, built in the 5th century BC during the Age of Pericles. The site has served as a religious centre, fortress, and treasury through Greek, Roman, Byzantine, Frankish, and Ottoman occupation.", category: "landmarks" },
  { question: "Where is the Great Pyramid of Giza?", answer: "Giza, Egypt", lat: 29.9792, lng: 31.1342, info: "The oldest and largest of the three pyramids in the Giza Necropolis, the Great Pyramid was built as a tomb for Pharaoh Khufu around 2560 BC using approximately 2.3 million stone blocks averaging 2.5 tonnes each. It stood as the world's tallest man-made structure for over 3,800 years, from its completion until the construction of Lincoln Cathedral in 1311.", category: "landmarks" },
  { question: "Where is the Inca Trail?", answer: "Cusco Region, Peru", lat: -13.5183, lng: -71.9784, info: "The most famous trekking route in South America follows a 43-kilometre ancient Inca road through the Peruvian Andes, passing through cloud forest, highland grassland, and Inca ruins before arriving at the Sun Gate overlooking Machu Picchu. The trail climbs to a highest pass of 4,215 metres at Dead Woman's Pass.", category: "landmarks" },
  { question: "Where is the Temple of Artemis?", answer: "Selçuk, Turkey", lat: 37.9499, lng: 27.3638, info: "The site of the Temple of Artemis at Ephesus, once one of the Seven Wonders of the Ancient World, was four times larger than the Parthenon and stood 18 metres tall supported by 127 columns. Destroyed and rebuilt multiple times, it was finally razed by the Goths in 268 AD; only a single column remains standing today.", category: "landmarks" },
  { question: "Where is Palmyra?", answer: "Homs Governorate, Syria", lat: 34.5503, lng: 38.2689, info: "The ancient Aramaic city that flourished as a major caravan oasis between the Mediterranean world and Mesopotamia contains remarkable Roman-era ruins including a colonnaded street, temple of Bel, and theatre. The site suffered devastating destruction at the hands of ISIS between 2015 and 2017, including the demolition of the Temple of Bel and the iconic Arch of Triumph.", category: "landmarks" },
  { question: "Where is the Colosseum of El Jem?", answer: "El Jem, Tunisia", lat: 35.2968, lng: 10.7074, info: "The third-largest Roman amphitheatre ever built and the best-preserved in the world outside Rome, the El Jem Colosseum was constructed around 238 AD and could hold 35,000 spectators. Carved into the surrounding town rather than standing free like its Roman counterpart, it was used as a fortress during the Arab conquest.", category: "landmarks" },
  { question: "Where is Leptis Magna?", answer: "Al Khums, Libya", lat: 32.6375, lng: 14.2958, info: "One of the best-preserved Roman cities in the world, Leptis Magna was the birthplace of Emperor Septimius Severus who lavished it with spectacular monuments including a forum, basilica, and triumphal arch in the late 2nd and early 3rd centuries AD. The city was largely buried by sand after its abandonment, which helped preserve it remarkably well.", category: "landmarks" },
  { question: "Where is the Colosseum of Verona?", answer: "Verona, Italy", lat: 45.4386, lng: 10.9941, info: "The Arena di Verona is a remarkably preserved Roman amphitheatre built in 30 AD and still used today as one of the world's most atmospheric open-air opera venues, hosting the famous annual Verona Opera Festival each summer. Seating up to 22,000 people, it is the third-largest surviving Roman amphitheatre after the Colosseum and El Jem.", category: "landmarks" },
  { question: "Where is Ephesus?", answer: "Selçuk, Turkey", lat: 37.9395, lng: 27.3417, info: "One of the best-preserved ancient cities in the Mediterranean world, Ephesus at its peak housed 200,000–500,000 inhabitants and was the second-largest city in the Roman Empire. Its marble-paved Curetes Street, Library of Celsus facade, and Grand Theatre where St Paul preached draw millions of visitors to its extensive excavated ruins.", category: "landmarks" },
  { question: "Where is the Church of the Nativity?", answer: "Bethlehem, Palestinian Territories", lat: 31.7042, lng: 35.2074, info: "Built over the traditional site of Jesus's birth, the Church of the Nativity was originally constructed by Emperor Constantine in 327 AD, making it one of the oldest continuously operating Christian churches in the world. The low doorway — known as the Door of Humility — was deliberately narrowed in the medieval period to prevent horsemen from riding in.", category: "landmarks" },
  { question: "Where is the Temple of Heaven?", answer: "Beijing, China", lat: 39.8822, lng: 116.4066, info: "The Temple of Heaven is a complex of Taoist buildings in Beijing where emperors of the Ming and Qing dynasties annually prayed for good harvests. The circular Hall of Prayer for Good Harvests (Qinian Dian), built in 1420, stands on three tiers of marble and is one of the most recognisable symbols of Chinese architecture, constructed entirely without nails.", category: "landmarks" },
  { question: "Where is the Colosseum of Nîmes?", answer: "Nîmes, France", lat: 43.8367, lng: 4.3601, info: "The Nîmes amphitheatre, built around 100 AD, is the best-preserved Roman amphitheatre in the world, capable of seating 24,000 spectators. Unlike many ancient theatres converted to other uses, it still hosts bullfights and concerts today, connecting modern audiences directly to the building's 2,000-year tradition of public spectacle.", category: "landmarks" },
];

export const NATURE_EVENTS = [
  { question: "Where is Mount Everest?", answer: "Nepal/Tibet border", lat: 27.9881, lng: 86.9250, info: "At 8,849 metres, Everest is the world's highest peak above sea level, first summited by Edmund Hillary and Tenzing Norgay on 29 May 1953. Over 300 climbers have died attempting to reach its summit, and the bodies of many remain on the mountain due to the extreme conditions making retrieval impossible.", category: "nature" },
  { question: "Where is K2?", answer: "Pakistan/China border", lat: 35.8825, lng: 76.5133, info: "At 8,611 metres, K2 is the world's second-highest mountain but widely considered far more dangerous than Everest with a fatality rate of roughly one death for every four summits. Known as the 'Savage Mountain', it was first climbed in 1954 by an Italian expedition and has never been summited in winter until a Pakistani-Nepali team achieved it in January 2021.", category: "nature" },
  { question: "Where is Mount Kilimanjaro?", answer: "Tanzania", lat: -3.0674, lng: 37.3556, info: "Africa's highest peak at 5,895 metres is the world's tallest free-standing mountain, rising dramatically from the surrounding plains in northern Tanzania near the Kenyan border. It is one of the seven summits and can be climbed without technical equipment, though altitude sickness claims many would-be summiteers.", category: "nature" },
  { question: "Where is Mont Blanc?", answer: "France/Italy border", lat: 45.8326, lng: 6.8652, info: "Western Europe's highest peak at 4,808 metres straddles the border between France and Italy in the Graian Alps and was first climbed in 1786. The mountain is a major alpine destination drawing around 20,000 summit attempts per year, and concerns are growing as climate change causes its summit height to fluctuate and glaciers to retreat.", category: "nature" },
  { question: "Where is Mount Aconcagua?", answer: "Mendoza Province, Argentina", lat: -32.6532, lng: -70.0110, info: "At 6,961 metres, Aconcagua is the Western and Southern Hemisphere's highest peak and the highest outside Asia. Located in the Andes near the Chilean border, it can be climbed via non-technical routes but extreme altitude and unpredictable weather make it a serious mountaineering challenge.", category: "nature" },
  { question: "Where is Denali?", answer: "Alaska, USA", lat: 63.0692, lng: -151.0070, info: "North America's highest peak at 6,190 metres, Denali (formerly Mt McKinley) sits at a subarctic latitude that makes it one of the most challenging high-altitude mountains due to severe weather, extreme cold, and the physiological effects of its far-northern position. First summited in 1913 by Hudson Stuck and companions.", category: "nature" },
  { question: "Where is Mount Olympus?", answer: "Thessaly/Macedonia, Greece", lat: 40.0866, lng: 22.3558, info: "At 2,918 metres, Olympus is Greece's highest mountain and was considered the home of the twelve Olympian gods in ancient Greek religion. Its imposing rugged profile visible from both the Aegean Sea and the Macedonian plains made it seem inaccessible to ancient Greeks, though it was first climbed in 1913.", category: "nature" },
  { question: "Where is Mount Fuji?", answer: "Honshu, Japan", lat: 35.3606, lng: 138.7274, info: "Japan's highest peak at 3,776 metres is a nearly perfectly symmetrical stratovolcano that has become one of the world's most painted and photographed mountains. Considered sacred in Shinto and Buddhist traditions, Fuji last erupted in 1707 and draws around 300,000 climbers to its summit each year during the official climbing season.", category: "nature" },
  { question: "Where is Mount Vesuvius?", answer: "Campania, Italy", lat: 40.8210, lng: 14.4260, info: "The only active volcano on mainland Europe, Vesuvius is infamous for its catastrophic eruption in 79 AD that buried Pompeii and Herculaneum under metres of ash, killing thousands. Although its last eruption was in 1944, it is considered one of the world's most dangerous volcanoes due to the 3 million people living in its shadow.", category: "nature" },
  { question: "Where is Mount Etna?", answer: "Sicily, Italy", lat: 37.7510, lng: 14.9934, info: "Europe's highest and most active volcano, Etna stands 3,357 metres tall and has erupted frequently throughout recorded history, with almost continuous activity in recent years. The fertile volcanic soils on its flanks support vineyards, orchards, and farms, with small towns nestled surprisingly close to its active craters.", category: "nature" },
  { question: "Where is Krakatoa?", answer: "Sunda Strait, Indonesia", lat: -6.1021, lng: 105.4231, info: "The 1883 eruption of Krakatoa was one of the deadliest volcanic events in recorded history, killing approximately 36,000 people and generating a tsunami 30 metres high. The explosion was heard as far away as Australia and the shock wave circled the globe multiple times; the new island Anak Krakatau ('Child of Krakatoa') emerged from the caldera in 1927.", category: "nature" },
  { question: "Where is Popocatépetl?", answer: "Puebla/Morelos/Mexico State, Mexico", lat: 19.0228, lng: -98.6277, info: "One of North America's most active volcanoes at 5,426 metres, 'El Popo' has erupted frequently in recent years and poses a major risk to the 25 million people living within 100 kilometres, including Mexico City. The Aztecs gave it its name meaning 'Smoking Mountain' and it features in numerous pre-Columbian legends.", category: "nature" },
  { question: "Where is the Matterhorn?", answer: "Switzerland/Italy border", lat: 45.9763, lng: 7.6586, info: "The Matterhorn's iconic four-sided pyramidal peak rising to 4,478 metres is one of the Alps' most recognisable and challenging mountains, with its near-vertical faces attracting climbers since Edward Whymper's first ascent in 1865 — which killed four of his seven party members on the descent. It is depicted on the Toblerone chocolate packaging.", category: "nature" },
  { question: "Where is Ben Nevis?", answer: "Scottish Highlands, Scotland", lat: 56.7969, lng: -5.0036, info: "At 1,345 metres, Ben Nevis is the highest peak in both Scotland and the British Isles, and its summit is cloud-covered about 355 days a year. The mountain has a well-maintained tourist path on its southern side and vertical cliffs of over 600 metres on its northern face popular with climbers.", category: "nature" },
  { question: "Where is Table Mountain?", answer: "Cape Town, South Africa", lat: -33.9628, lng: 18.4098, info: "The flat-topped mountain overlooking Cape Town is one of the world's oldest mountains at around 600 million years old and is home to an extraordinarily rich endemic flora — more plant species per square kilometre than anywhere else on Earth. A cable car opened in 1929 carries visitors to the summit 1,086 metres above sea level.", category: "nature" },
  { question: "Where is Uluru?", answer: "Northern Territory, Australia", lat: -25.3444, lng: 131.0369, info: "This massive sandstone monolith rises 348 metres from the flat desert of central Australia and stretches 9.4 kilometres in circumference, though most of its bulk lies underground. Sacred to the Anangu Aboriginal people for thousands of years, Uluru was returned to Aboriginal ownership in 1985 and climbing was permanently banned in 2019.", category: "nature" },
  { question: "Where is Mount Roraima?", answer: "Venezuela/Brazil/Guyana border", lat: 5.1430, lng: -60.7619, info: "This tabletop mountain (tepui) rises 2,810 metres and is so flat-topped that it influenced Arthur Conan Doyle to write The Lost World, imagining prehistoric creatures isolated atop it. Its unique ecosystem contains species found nowhere else on Earth and its permanent cloud cover produces rain that washes the summit's bare rock almost clean of nutrients.", category: "nature" },
  { question: "Where is Chimborazo?", answer: "Chimborazo Province, Ecuador", lat: -1.4689, lng: -78.8167, info: "Although only 6,263 metres above sea level, Chimborazo's equatorial location means its summit is the point on Earth's surface farthest from the planet's centre — farther than Everest's summit by over 2 kilometres. Its extinct volcanic cone was long believed by Europeans to be the world's highest peak until proper surveying of the Himalayas.", category: "nature" },
  { question: "Where is the Amazon River?", answer: "South America", lat: -3.4653, lng: -62.2159, info: "The Amazon carries about 20% of all freshwater flowing into the world's oceans and its basin covers 7 million square kilometres, home to 10% of all species on Earth. While the Nile is marginally longer, the Amazon's discharge is so enormous that it discharges more water than the next seven largest rivers combined.", category: "nature" },
  { question: "Where is the Nile River?", answer: "Northeast Africa", lat: 26.8206, lng: 30.8025, info: "The Nile is generally regarded as the world's longest river at approximately 6,650 kilometres, flowing northward from its source in the Burundi highlands through 11 countries to its Mediterranean delta. Ancient Egyptian civilisation was built entirely on the Nile's annual floods, which deposited rich silt on the surrounding desert.", category: "nature" },
  { question: "Where is the Yangtze River?", answer: "China", lat: 30.5928, lng: 114.3055, info: "Asia's longest and the world's third-longest river at 6,300 kilometres, the Yangtze originates on the Tibetan Plateau and flows through the spectacular Three Gorges before reaching the East China Sea near Shanghai. The Three Gorges Dam, completed in 2006 on the Yangtze, is the world's largest hydroelectric power station.", category: "nature" },
  { question: "Where is the Mississippi River?", answer: "Central USA", lat: 38.6270, lng: -90.1994, info: "The Mississippi and its tributary the Missouri together form North America's largest river system at 3,730 kilometres, draining all or part of 31 US states. Mark Twain immortalised the river in his novels and it remains a vital commercial waterway, carrying goods from the agricultural heartland to the Gulf of Mexico.", category: "nature" },
  { question: "Where is the Congo River?", answer: "Central Africa", lat: -4.3200, lng: 15.3222, info: "The world's second-largest river by discharge and deepest river on Earth, the Congo reaches depths of over 220 metres and carries about 41,000 cubic metres of water per second to the Atlantic. It crosses the equator twice and powers the Grand Inga hydroelectric project site, which if completed would be the world's largest.", category: "nature" },
  { question: "Where is the Volga River?", answer: "Russia", lat: 56.1366, lng: 47.2536, info: "Europe's longest river at 3,531 kilometres drains about 40% of European Russia into the Caspian Sea. The Volga has been central to Russian culture and history for millennia and today carries about 60% of Russia's river traffic, linking the Baltic to the Caspian via a system of canals.", category: "nature" },
  { question: "Where is the Rhine River?", answer: "Western Europe", lat: 51.8000, lng: 6.1000, info: "Rising in the Swiss Alps and flowing 1,230 kilometres to the North Sea in the Netherlands, the Rhine is one of Europe's most important commercial waterways, bordered by medieval castles, vineyards, and industrial cities. The Rhine Valley between Bingen and Koblenz is a UNESCO World Heritage Site for its cultural landscape.", category: "nature" },
  { question: "Where is the Danube River?", answer: "Central/Eastern Europe", lat: 44.8186, lng: 20.4572, info: "Europe's second-longest river at 2,860 kilometres flows through 10 countries from its source in Germany's Black Forest to its delta on the Romanian/Ukrainian Black Sea coast. The Danube passes through four capital cities — Vienna, Bratislava, Budapest, and Belgrade — more than any other river in the world.", category: "nature" },
  { question: "Where is the Ganges River?", answer: "India/Bangladesh", lat: 25.3176, lng: 83.0061, info: "Hinduism's holiest river flows 2,525 kilometres from the Gangotri Glacier in the Himalayas to its delta in Bangladesh and West India, where it merges with the Brahmaputra to form the Sundarbans mangrove forest. Around 400 million people live in the Ganges basin and rely on it for drinking water, irrigation, and religious ceremonies.", category: "nature" },
  { question: "Where is the Mekong River?", answer: "Southeast Asia", lat: 13.1000, lng: 105.8600, info: "The world's 12th-longest river at 4,350 kilometres originates on the Tibetan Plateau and flows through China, Myanmar, Laos, Thailand, Cambodia, and Vietnam, supporting the livelihoods of 60 million people. The Mekong's Tonle Sap in Cambodia is one of the world's most productive freshwater fisheries due to the river's extraordinary seasonal flood pulse.", category: "nature" },
  { question: "Where is the Tigris River?", answer: "Turkey/Iraq", lat: 33.3152, lng: 44.3661, info: "The Tigris flows 1,850 kilometres from its source in eastern Turkey through Iraq to the Persian Gulf, along with the Euphrates forming the Mesopotamian heartland where some of the earliest civilisations including Sumer, Akkad, and Babylon arose. Baghdad sits on its banks and it remains vital for Iraqi agriculture despite declining flows from dams upstream.", category: "nature" },
  { question: "Where is the Niger River?", answer: "West Africa", lat: 5.3350, lng: 6.4498, info: "Africa's third-longest river at 4,180 kilometres traces a massive arc through Guinea, Mali, Niger, Benin, and Nigeria before reaching its delta in the Gulf of Guinea. The unusual boomerang shape of its course baffled 18th century European cartographers; the river's inland delta in Mali creates a vast seasonal floodplain of remarkable biodiversity.", category: "nature" },
  { question: "Where is the Zambezi River?", answer: "Southern Africa", lat: -15.5833, lng: 30.3833, info: "The Zambezi flows 2,574 kilometres from its source in Zambia to the Indian Ocean in Mozambique, passing through six countries and dropping spectacularly over Victoria Falls. The river's middle section is damned by the Kariba and Cahora Bassa dams, creating two of Africa's largest reservoirs.", category: "nature" },
  { question: "Where is Lake Baikal?", answer: "Siberia, Russia", lat: 53.5587, lng: 108.1650, info: "Lake Baikal is the world's deepest lake at 1,642 metres and holds approximately 20% of the world's unfrozen surface fresh water. At 25–30 million years old, it is also the world's oldest lake and home to the Baikal seal (nerpa), one of the world's only exclusively freshwater seals, and thousands of endemic species.", category: "nature" },
  { question: "Where is Lake Superior?", answer: "USA/Canada border", lat: 47.7000, lng: -87.5000, info: "Lake Superior is the world's largest freshwater lake by surface area at 82,100 square kilometres, containing about 10% of the world's surface fresh water. So large that it creates its own weather patterns, it earned a reputation as a ship graveyard — over 350 ships have sunk in its waters.", category: "nature" },
  { question: "Where is Lake Titicaca?", answer: "Peru/Bolivia border", lat: -15.8402, lng: -69.3354, info: "At 3,812 metres above sea level, Lake Titicaca is the world's highest navigable lake and South America's largest by volume. The Uros people construct and live on floating islands made of totora reeds on its surface, and Inca legend holds that the god Viracocha emerged from the lake's depths to create the sun, moon, and first humans.", category: "nature" },
  { question: "Where is Lake Victoria?", answer: "East Africa", lat: -1.0000, lng: 33.0000, info: "Africa's largest lake and the world's second-largest freshwater lake by surface area at 68,800 square kilometres, Lake Victoria is shared by Tanzania, Uganda, and Kenya and is the source of the White Nile. The introduction of Nile perch in the 1950s caused the extinction of hundreds of endemic cichlid fish species in what has been called the world's worst freshwater ecological disaster.", category: "nature" },
  { question: "Where is Lake Tanganyika?", answer: "East/Central Africa", lat: -6.0000, lng: 29.5000, info: "The world's second-deepest lake at 1,470 metres and second-largest by volume, Lake Tanganyika forms part of the Great Rift Valley and is bordered by Burundi, Tanzania, Zambia, and the Democratic Republic of Congo. It is so ancient — around 10 million years old — that it has evolved a unique marine-like fauna including jellyfish, crabs, and over 350 species of cichlid fish.", category: "nature" },
  { question: "Where is the Dead Sea?", answer: "Israel/Jordan border", lat: 31.5590, lng: 35.4732, info: "At 430 metres below sea level, the Dead Sea is the lowest point on Earth's surface, and its water is nearly 10 times saltier than ocean water, making it impossible for most organisms to survive — hence its name. The high salt concentration allows swimmers to float effortlessly and the mineral-rich mud is prized for therapeutic and cosmetic properties.", category: "nature" },
  { question: "Where is the Caspian Sea?", answer: "Central Asia/Eastern Europe", lat: 42.0000, lng: 51.0000, info: "The world's largest enclosed body of water at 371,000 square kilometres is technically a lake, bordered by Russia, Kazakhstan, Turkmenistan, Iran, and Azerbaijan. It contains 90% of the world's sturgeon, which produce the prized beluga caviar, though sturgeon populations have collapsed due to overfishing and pollution.", category: "nature" },
  { question: "Where is Crater Lake?", answer: "Oregon, USA", lat: 42.9446, lng: -122.1090, info: "Formed around 7,700 years ago after the massive volcanic eruption of Mount Mazama collapsed the peak, Crater Lake is the deepest lake in the United States at 594 metres. Its extraordinary clarity — it has some of the clearest water of any lake in the world — and intense blue colour result from its depth and the absence of significant inflowing rivers.", category: "nature" },
  { question: "Where is Loch Ness?", answer: "Scottish Highlands, Scotland", lat: 57.3229, lng: -4.4244, info: "Stretching 37 kilometres through the Great Glen fault valley, Loch Ness contains more freshwater than all the lakes in England and Wales combined, with a depth of 230 metres. It is world-famous for the 'Nessie' legend, perpetuated since a 1933 newspaper story; scientific surveys have found no evidence of a large animal but the loch remains one of Scotland's most visited attractions.", category: "nature" },
  { question: "Where are the Angel Falls?", answer: "Bolívar State, Venezuela", lat: 5.9677, lng: -62.5356, info: "Angel Falls is the world's highest uninterrupted waterfall at 979 metres, plunging from the flat summit of Auyán-tepui mountain in the Gran Sabana region. Named after American aviator Jimmie Angel who flew over them in 1933, they are known locally as Kerepakupai Merú meaning 'waterfall of the deepest place'.", category: "nature" },
  { question: "Where is Niagara Falls?", answer: "USA/Canada border", lat: 43.0799, lng: -79.0748, info: "Niagara Falls comprises three waterfalls — Horseshoe Falls, American Falls, and Bridal Veil Falls — on the border between Ontario and New York State, with a combined flow rate making them the most powerful waterfall in North America. The falls have been receding upstream at a rate of about 1 metre per year due to erosion.", category: "nature" },
  { question: "Where is Iguazu Falls?", answer: "Argentina/Brazil border", lat: -25.6953, lng: -54.4367, info: "Stretching nearly 3 kilometres wide with 275 individual cascades, Iguazu Falls is the world's largest waterfall system by width. Eleanor Roosevelt reportedly exclaimed 'Poor Niagara!' upon seeing them; the Devil's Throat U-shaped chasm drops 82 metres and creates a permanent cloud of mist visible from miles away.", category: "nature" },
  { question: "Where is Victoria Falls?", answer: "Zambia/Zimbabwe border", lat: -17.9244, lng: 25.8567, info: "Victoria Falls, known locally as Mosi-oa-Tunya ('The Smoke That Thunders'), is the world's largest sheet of falling water at 1.7 kilometres wide and 108 metres tall. David Livingstone became the first European to see it in 1855 and named it after Queen Victoria; the spray rises 400 metres and can be seen 50 kilometres away.", category: "nature" },
  { question: "Where are the Kaieteur Falls?", answer: "Potaro-Siparuni, Guyana", lat: 5.1742, lng: -59.4828, info: "Kaieteur Falls on the Potaro River drops 226 metres in a single plunge — about four times the height of Niagara — making it the world's largest single-drop waterfall by volume of water. Located in a remote part of the Guiana Highlands accessible only by small aircraft, it sees far fewer tourists than better-known falls.", category: "nature" },
  { question: "Where is the Sahara Desert?", answer: "North Africa", lat: 23.4162, lng: 25.6628, countryCode: "REGION", info: "The Sahara is the world's largest hot desert at 9.2 million square kilometres, covering most of North Africa from the Atlantic to the Red Sea. Despite its image as endless sand dunes, about 70% of the Sahara is rocky hamada plateaus; the famous ergs (sand seas) represent only a small fraction of its total area.", category: "nature" },
  { question: "Where is the Gobi Desert?", answer: "Mongolia/China", lat: 42.5897, lng: 103.4246, info: "The Gobi stretches 1.3 million square kilometres across Mongolia and northern China and is the world's fifth-largest desert as well as the largest in Asia. Unlike the Sahara, the Gobi is a cold desert where temperatures can range from -40°C in winter to +50°C in summer, and it is underlain by some of the world's richest dinosaur fossil beds.", category: "nature" },
  { question: "Where is the Atacama Desert?", answer: "Chile/Peru", lat: -24.5000, lng: -69.2500, info: "The Atacama is the world's driest non-polar desert, with some weather stations recording no rainfall at all for decades; parts of it may not have received significant rain for 500 years. Despite its extreme aridity, it hosts unique flora adapted to coastal fog, rare brine lakes, and is used to test Mars rovers due to its Mars-like conditions.", category: "nature" },
  { question: "Where is the Arabian Desert?", answer: "Arabian Peninsula", lat: 22.0000, lng: 46.0000, countryCode: "REGION", info: "The Arabian Desert covering 2.3 million square kilometres across most of the Arabian Peninsula is the world's fourth-largest desert and home to the Rub' al Khali (Empty Quarter), the largest continuous sand desert on Earth at 650,000 square kilometres. Despite its inhospitable conditions, the desert sits atop the world's largest proven oil reserves.", category: "nature" },
  { question: "Where is the Great Victoria Desert?", answer: "Western/South Australia, Australia", lat: -29.0000, lng: 126.9000, info: "Australia's largest desert at 424,000 square kilometres, the Great Victoria Desert spans the border between Western Australia and South Australia and consists largely of red sand dunes and gibber plains. It is one of the world's most intact desert ecosystems, home to diverse reptiles and Aboriginal communities who have lived there for tens of thousands of years.", category: "nature" },
  { question: "Where is the Namib Desert?", answer: "Namibia", lat: -24.0000, lng: 15.0000, info: "Considered the world's oldest desert at 55–80 million years old, the Namib stretches along Africa's Atlantic coast for 2,000 kilometres and gave Namibia its name. Its star dunes near Sossusvlei are among the world's tallest, reaching 325 metres, and the desert supports unique fog-dependent flora and the extraordinary Welwitschia plant, individual specimens of which can live for over 1,000 years.", category: "nature" },
  { question: "Where is the Patagonian Desert?", answer: "Argentina", lat: -44.0000, lng: -68.0000, info: "South America's largest desert covering 673,000 square kilometres in southern Argentina is a cold desert in the rain shadow of the Andes. Despite its harsh conditions, Patagonia supports guanacos, rheas, pumas, and the world's largest colony of Magellanic penguins at Punta Tombo.", category: "nature" },
  { question: "Where is the Sonoran Desert?", answer: "USA/Mexico", lat: 32.0000, lng: -113.0000, info: "The Sonoran Desert spans 310,000 square kilometres across the southwestern United States and northwestern Mexico and is considered the hottest desert in North America. It is one of the most biologically diverse deserts in the world and is the only place on Earth where the saguaro cactus grows naturally, with individuals living over 150 years and reaching 15 metres tall.", category: "nature" },
  { question: "Where is the Kalahari Desert?", answer: "Southern Africa", lat: -23.0000, lng: 22.0000, countryCode: "REGION", info: "Technically a semi-desert rather than a true desert, the Kalahari covers 930,000 square kilometres across Botswana, Namibia, and South Africa. The San (Bushmen) people have lived here for at least 20,000 years, and the desert supports large wildlife populations including the famous black-maned Kalahari lions.", category: "nature" },
  { question: "Where is the Thar Desert?", answer: "India/Pakistan border", lat: 27.0000, lng: 71.0000, info: "The Thar Desert, or Great Indian Desert, covers about 200,000 square kilometres making it the world's 17th largest desert and the most densely populated desert in the world with about 83 people per square kilometre. Camel fairs, ancient forts, and colourful textiles make it a major tourist destination; the city of Jaisalmer rises like a sandcastle from its heart.", category: "nature" },
  { question: "Where is the Great Barrier Reef?", answer: "Queensland, Australia", lat: -18.2871, lng: 147.6992, info: "The world's largest coral reef system stretches over 2,300 kilometres along the Queensland coast and is composed of over 2,900 individual reefs and 900 islands. Visible from space, it supports extraordinary biodiversity including 1,500 fish species, 4,000 types of mollusc, and 240 bird species, but has experienced severe bleaching events due to rising ocean temperatures.", category: "nature" },
  { question: "Where is the Mariana Trench?", answer: "Western Pacific Ocean", lat: 11.3733, lng: 142.5917, info: "The deepest point on Earth's surface, the Challenger Deep in the Mariana Trench plunges approximately 10,935 metres below sea level — deep enough to submerge Mount Everest with over a kilometre to spare. Despite the crushing pressure, total darkness, and freezing temperatures, scientists have found bacteria, small crustaceans, and even plastic bags there.", category: "nature" },
  { question: "Where is the Coral Triangle?", answer: "Southeast Asia/Pacific", lat: 2.0000, lng: 126.0000, countryCode: "REGION", info: "Covering 6 million square kilometres of ocean across Indonesia, Malaysia, Papua New Guinea, Philippines, Solomon Islands, and Timor-Leste, the Coral Triangle is the global centre of marine biodiversity, containing 76% of all known coral species and the habitats for over 3,000 species of fish. It is known as the 'Amazon of the Seas' and supports the livelihoods of 120 million people.", category: "nature" },
  { question: "Where is the Amazon Rainforest?", answer: "South America", lat: -3.4653, lng: -62.2159, countryCode: "REGION", info: "The world's largest tropical rainforest covers 5.5 million square kilometres across nine countries and represents over half of the planet's remaining rainforests. It produces about 20% of the world's oxygen, is home to 10% of all species on Earth, and stores an estimated 150–200 billion tonnes of carbon — making its preservation critical to climate stability.", category: "nature" },
  { question: "Where is the Congo Rainforest?", answer: "Central Africa", lat: -1.0000, lng: 24.0000, countryCode: "REGION", info: "The Congo Rainforest is the world's second-largest tropical rainforest at 3.3 million square kilometres and the most biodiverse in Africa, home to gorillas, bonobos, forest elephants, and okapis. Unlike the Amazon, it has remained relatively intact with deforestation rates historically lower, though logging and agricultural pressure are increasing.", category: "nature" },
  { question: "Where is Yellowstone National Park?", answer: "Wyoming/Montana/Idaho, USA", lat: 44.4280, lng: -110.5885, info: "The world's first national park established in 1872 sits atop a supervolcano whose magma chamber holds enough molten rock to fill the Grand Canyon 11 times. Yellowstone's 10,000 hydrothermal features — geysers, hot springs, mudpots, and fumaroles — represent roughly half of all such features on Earth, including Old Faithful which erupts every 60–110 minutes.", category: "nature" },
  { question: "Where is the Serengeti?", answer: "Tanzania/Kenya", lat: -2.1540, lng: 34.6857, info: "The Serengeti ecosystem spanning about 30,000 square kilometres in Tanzania and Kenya hosts the world's largest overland migration, with 1.5 million wildebeest and hundreds of thousands of zebra and gazelle moving annually in a clockwise circuit following the rains. The word 'Serengeti' comes from the Maasai language meaning 'endless plains'.", category: "nature" },
  { question: "Where is the Daintree Rainforest?", answer: "Queensland, Australia", lat: -16.1700, lng: 145.4180, info: "The Daintree is the world's oldest continuously surviving tropical rainforest, estimated to be around 180 million years old — predating the Amazon by over 100 million years. Located in northeastern Queensland, it is one of the few places where tropical rainforest meets the ocean and contains species found nowhere else, including the cassowary.", category: "nature" },
  { question: "Where is the Borneo Rainforest?", answer: "Borneo, Southeast Asia", lat: 0.9619, lng: 114.5548, info: "Borneo's rainforest is one of the oldest in the world at around 130 million years and is the most biodiverse in Southeast Asia, home to pygmy elephants, proboscis monkeys, clouded leopards, and the critically endangered orangutan. Deforestation for palm oil and timber has reduced its extent by over 50% since the 1970s.", category: "nature" },
  { question: "Where is the Tongass National Forest?", answer: "Alaska, USA", lat: 57.0000, lng: -133.5000, info: "The largest national forest in the United States at 6.8 million hectares, the Tongass covers most of the Alaska Panhandle with temperate rainforest. It stores more carbon per hectare than any other forest in North America and is home to some of the world's largest Sitka spruce and western red cedar, as well as the highest density of brown bears on Earth.", category: "nature" },
  { question: "Where is the Black Forest?", answer: "Baden-Württemberg, Germany", lat: 48.0000, lng: 8.2000, info: "The Schwarzwald in southwestern Germany is the largest continuous forested area in Germany, covering 6,000 square kilometres of densely wooded mountains rising to 1,493 metres at the Feldberg. It inspired the Brothers Grimm fairy tales, lent its name to Black Forest gateau, and is home to the source of the Danube River.", category: "nature" },
  { question: "Where is the Białowieża Forest?", answer: "Poland/Belarus border", lat: 52.7077, lng: 23.8600, info: "One of the last and largest remaining parts of the primeval forest that once covered the European Plain, Białowieża straddles the Polish-Belarusian border and is home to the European bison (wisent), which was hunted to extinction in the wild by 1927 and successfully reintroduced through a captive breeding programme. Its ancient oaks are up to 500 years old.", category: "nature" },
  { question: "Where is the Sundarbans?", answer: "Bangladesh/India", lat: 21.9497, lng: 89.1833, info: "The Sundarbans is the world's largest mangrove forest at 10,000 square kilometres, shared between Bangladesh (60%) and India (40%), where the Ganges, Brahmaputra, and Meghna rivers meet the Bay of Bengal. It is the only mangrove ecosystem in the world inhabited by tigers, which have adapted to swim between islands and occasionally prey on humans.", category: "nature" },
  { question: "Where are the Galápagos Islands?", answer: "Ecuador", lat: -0.9538, lng: -90.9656, info: "These volcanic islands 1,000 kilometres off Ecuador's coast inspired Charles Darwin's theory of evolution by natural selection during his 1835 visit, when he observed how species — particularly finches and tortoises — had adapted differently on each island. Unique animals including marine iguanas, flightless cormorants, and giant tortoises still live there with little fear of humans.", category: "nature" },
  { question: "Where is Madagascar?", answer: "Madagascar", lat: -18.7669, lng: 46.8691, countryCode: "MG", info: "The world's fourth-largest island has been isolated from mainland Africa for around 88 million years, allowing evolution to proceed in its own direction — over 90% of its wildlife is found nowhere else on Earth. Madagascar is home to all the world's lemur species and a remarkable diversity of chameleons, baobabs, and tenrecs.", category: "nature" },
  { question: "Where is Greenland?", answer: "Greenland", lat: 71.7069, lng: -42.6043, countryCode: "GL", info: "The world's largest island at 2.1 million square kilometres is covered by the Greenland Ice Sheet, which contains about 8% of the world's fresh water and, if fully melted, would raise global sea levels by around 7 metres. Home to around 56,000 people, mostly Inuit, Greenland is an autonomous territory within the Kingdom of Denmark.", category: "nature" },
  { question: "Where is Iceland?", answer: "Iceland", lat: 64.9631, lng: -19.0208, countryCode: "IS", info: "Straddling the Mid-Atlantic Ridge where two tectonic plates diverge, Iceland is one of the world's most geologically active places with around 130 volcanoes, including the subglacial Öraefajökull which holds Europe's largest glacier. Despite its name, Iceland is notably green during summer, while Greenland's coasts are ice-free for only a few months.", category: "nature" },
  { question: "Where are the Hawaiian Islands?", answer: "Hawaii, USA", lat: 20.7967, lng: -156.3319, info: "The Hawaiian archipelago formed by a volcanic hotspot that has punched through the Pacific Plate over millions of years, creating a chain of islands with the youngest and most volcanically active (the Big Island) at the southeastern end. Hawaii is the world's most isolated archipelago and has the highest rate of endemic species, earning it the nickname 'the extinction capital of the world'.", category: "nature" },
  { question: "Where are the Maldives?", answer: "Maldives", lat: 3.2028, lng: 73.2207, countryCode: "MV", info: "The world's lowest-lying country with a maximum natural ground level of just 2.4 metres above sea level, the Maldives consists of 1,200 coral islands across 26 atolls in the Indian Ocean. The country faces an existential threat from rising sea levels caused by climate change and has held underwater cabinet meetings to highlight this danger.", category: "nature" },
  { question: "Where is the Grand Canyon?", answer: "Arizona, USA", lat: 36.1070, lng: -112.1130, info: "Carved by the Colorado River over 5–6 million years, the Grand Canyon is 446 kilometres long, up to 29 kilometres wide, and over 1.6 kilometres deep. The exposed rock strata represent nearly 2 billion years of Earth's geological history, with the Colorado River still at work carving it deeper by around 30 centimetres per thousand years.", category: "nature" },
  { question: "Where is the Great Rift Valley?", answer: "East Africa", lat: 0.5000, lng: 36.0000, countryCode: "REGION", info: "The East African Rift is a 6,000-kilometre active continental rift stretching from the Afar Triangle in the north to Mozambique in the south, where the African tectonic plate is slowly splitting into two. The rift created East Africa's iconic chain of lakes including Tanganyika, Malawi, and the Albertine lakes, and is theorised to have driven human evolution by creating savanna habitats.", category: "nature" },
  { question: "Where is Cappadocia?", answer: "Central Anatolia, Turkey", lat: 38.6431, lng: 34.8289, info: "Cappadocia's extraordinary landscape of 'fairy chimneys' — tall, thin cones of soft volcanic tuff topped by harder rock — was formed by millions of years of erosion of ancient volcanic deposits. Early Christians carved elaborate underground cities, cave churches, and monasteries into the soft rock; today the area is world-famous for dawn hot-air balloon flights over the surreal landscape.", category: "nature" },
  { question: "Where is Pamukkale?", answer: "Denizli Province, Turkey", lat: 37.9213, lng: 29.1211, info: "Pamukkale ('Cotton Castle' in Turkish) is a natural site of white carbonate terraces formed by calcium-rich thermal spring waters cascading down a hillside and depositing travertine over thousands of years. At the top sit the ruins of Hierapolis, an ancient Greco-Roman spa city founded around 190 BC to take advantage of the therapeutic waters.", category: "nature" },
  { question: "Where are the Waitomo Glowworm Caves?", answer: "Waikato, New Zealand", lat: -38.2605, lng: 175.1037, info: "The Waitomo Caves are famous for their resident population of Arachnocampa luminosa, a species of glowworm found only in New Zealand, whose bioluminescent larvae create a stunning blue-green starfield effect on the cave ceilings. The caves also contain spectacular limestone formations including stalactites, stalagmites, and a 14,000-year-old stalactite cathedral.", category: "nature" },
  { question: "Where are the Carlsbad Caverns?", answer: "New Mexico, USA", lat: 32.1479, lng: -104.5567, info: "Carlsbad Caverns in the Guadalupe Mountains contains over 119 limestone caves, including the Big Room — one of the largest cave chambers in North America at 550 metres long and 255 metres wide. Each evening from May to October, around 400,000 Brazilian free-tailed bats spiral up from the cave entrance in a dramatic spectacle that lasts several hours.", category: "nature" },
  { question: "Where is Reed Flute Cave?", answer: "Guilin, China", lat: 25.2410, lng: 110.2580, info: "Named after the reeds growing near its entrance that were historically made into flutes, Reed Flute Cave is a 240-metre-long natural limestone cave in Guilin containing spectacular stalagmites, stalactites, and rock formations illuminated with colourful lights. Chinese inscriptions on its walls date back to the Tang dynasty (618–907 AD), showing it has been a tourist attraction for over 1,200 years.", category: "nature" },
  { question: "Where is the Giant's Causeway?", answer: "County Antrim, Northern Ireland", lat: 55.2408, lng: -6.5116, info: "The Giant's Causeway consists of approximately 40,000 interlocking basalt columns formed by an ancient volcanic eruption around 50–60 million years ago; most are hexagonal, though some have four, five, seven, or eight sides. Local legend attributes the columns to the Irish giant Fionn mac Cumhaill, who built the causeway to walk to Scotland to fight his rival.", category: "nature" },
  { question: "Where is Wave Rock?", answer: "Western Australia, Australia", lat: -32.4414, lng: 118.8975, info: "Wave Rock is a natural rock formation shaped like a tall breaking ocean wave, standing 15 metres high and 110 metres long, formed by chemical weathering and erosion over 2.7 billion years. The vivid stripes of colour on its face are caused by concentrated acids leaching down the face and depositing minerals including iron hydroxides and carbonates.", category: "nature" },
  { question: "Where is the Perito Moreno Glacier?", answer: "Santa Cruz Province, Argentina", lat: -50.4956, lng: -73.0771, info: "One of the world's most accessible and spectacular glaciers, Perito Moreno is 30 kilometres long and covers 250 square kilometres in Los Glaciares National Park. Unlike most glaciers, it remains stable or even advances slightly due to heavy snowfall feeding it; periodically its ice dam ruptures with tremendous noise, sending house-sized icebergs crashing into Lake Argentino.", category: "nature" },
  { question: "Where is the Franz Josef Glacier?", answer: "West Coast, New Zealand", lat: -43.4553, lng: 170.1847, info: "Franz Josef is one of the world's most accessible glaciers, descending from the Southern Alps to just 300 metres above sea level through temperate rainforest — an unusual combination. Named after the Austrian emperor by European explorer Julius von Haast in 1865, the glacier has been retreating significantly in recent decades due to climate change after centuries of relative stability.", category: "nature" },
  { question: "Where is the Columbia Icefield?", answer: "Alberta/British Columbia, Canada", lat: 52.1503, lng: -117.3244, info: "The largest icefield in the Rocky Mountains south of Alaska at 325 square kilometres, the Columbia Icefield is a hydrological apex from which meltwater drains to three different oceans: the Pacific, Atlantic, and Arctic. The Athabasca Glacier, its most accessible lobe, has retreated about 1.5 kilometres since 1890 and thinned by 40 metres.", category: "nature" },
  { question: "Where can you see the Northern Lights?", answer: "Tromsø, Norway", lat: 69.6496, lng: 18.9560, info: "Tromsø in northern Norway is one of the best places to see the Northern Lights (Aurora Borealis); it lies within the auroral oval where auroral activity is most intense. The phenomenon is caused by charged particles from the sun interacting with gases in Earth's atmosphere and can appear as green, red, purple, or blue curtains of light.", category: "nature" },
  { question: "Where is the Sargasso Sea?", answer: "North Atlantic Ocean", lat: 30.0000, lng: -65.0000, info: "The Sargasso Sea is the only sea in the world with no coastline, bounded entirely by ocean currents — the Gulf Stream to the west, the North Atlantic Current to the north, the Canary Current to the east, and the North Atlantic Equatorial Current to the south. Named for its vast mats of Sargassum seaweed, it is the only known breeding ground for both European and American eels.", category: "nature" },
  { question: "Where is the Bay of Fundy?", answer: "New Brunswick/Nova Scotia, Canada", lat: 45.3006, lng: -64.6988, info: "The Bay of Fundy between New Brunswick and Nova Scotia has the highest tidal range in the world, with tides reaching up to 16.3 metres — the height of a five-storey building — twice daily. This extraordinary tidal resonance is caused by the bay's funnel shape and depth matching the natural resonance frequency of the Atlantic basin's tidal oscillation.", category: "nature" },
  { question: "Where are the Chocolate Hills?", answer: "Bohol, Philippines", lat: 9.8958, lng: 124.1692, info: "The Chocolate Hills are an unusual geological formation of over 1,200 nearly perfectly conical grass-covered limestone hills spread across 50 square kilometres of Bohol Island. During the dry season the grass turns brown, making them resemble large chocolates — giving them their name; local legend attributes them to the tears of a heartbroken giant.", category: "nature" },
  { question: "Where is the Aral Sea?", answer: "Kazakhstan/Uzbekistan", lat: 45.0000, lng: 60.0000, info: "Once the world's fourth-largest lake at 68,000 square kilometres, the Aral Sea has shrunk to less than 10% of its original size since the 1960s due to Soviet irrigation projects diverting the Amu Darya and Syr Darya rivers. Its collapse is considered one of the world's worst environmental disasters; rusting ship hulks now sit kilometres from any water in what was once a thriving fishing industry.", category: "nature" },
  { question: "Where is Lake Malawi?", answer: "Malawi/Mozambique/Tanzania", lat: -12.0000, lng: 34.5000, info: "The southernmost lake of the African Great Lakes stretches 580 kilometres and contains more fish species than any other lake on Earth — over 1,000, of which around 90% are cichlids found nowhere else. Lake Malawi National Park, protecting its southern end, was the first freshwater national park in Africa.", category: "nature" },
  { question: "Where is Lake Huron?", answer: "USA/Canada border", lat: 44.7500, lng: -82.5000, info: "The second-largest of the Great Lakes at 59,600 square kilometres, Lake Huron is connected to Lake Michigan at the Straits of Mackinac, and some hydrologists treat them as one body of water. Manitoulin Island in Lake Huron is the world's largest freshwater island by area at 2,766 square kilometres.", category: "nature" },
  { question: "Where is Lake Michigan?", answer: "USA", lat: 44.0000, lng: -87.0000, info: "The only one of the five Great Lakes located entirely within the United States, Lake Michigan is the second-largest by volume and borders Illinois, Indiana, Michigan, and Wisconsin. Chicago's famous lakefront beaches face Lake Michigan, which is sometimes called the 'Third Coast' by Midwesterners.", category: "nature" },
  { question: "Where are the Sutherland Falls?", answer: "South Island, New Zealand", lat: -44.8167, lng: 167.7333, info: "Dropping 580 metres in three cascades, Sutherland Falls is the tallest waterfall in New Zealand and one of the highest in the world. Located in Fiordland National Park near the end of the Milford Track, it was named after Donald Sutherland who 'discovered' it in 1880 and was later a famous character known as 'the hermit of Milford Sound'.", category: "nature" },
  { question: "Where is the Murray-Darling Basin?", answer: "Southeastern Australia", lat: -33.0000, lng: 144.0000, info: "Australia's most important river system covers 1 million square kilometres — about 14% of the continent — and produces about 40% of Australia's agricultural output. The Murray-Darling system includes Australia's three longest rivers and drains an area roughly twice the size of France, though frequent droughts mean its flow is barely a fraction of rivers of similar catchment area in wetter regions.", category: "nature" },
  { question: "Where is the Antarctic Ice Sheet?", answer: "Antarctica", lat: -82.8628, lng: 135.0000, countryCode: "REGION", info: "The Antarctic Ice Sheet covers about 98% of Antarctica and is the largest single mass of ice on Earth, containing roughly 61% of all the world's fresh water. If it melted completely, global sea levels would rise by approximately 58 metres; the ice sheet in West Antarctica is considered the most vulnerable to collapse and could alone contribute 3.3 metres of sea level rise.", category: "nature" },
  { question: "Where is the Arctic Ocean?", answer: "Arctic Region", lat: 90.0000, lng: 0.0000, countryCode: "REGION", info: "The smallest and shallowest of the world's five oceans, the Arctic Ocean is largely covered by sea ice which fluctuates seasonally but has been shrinking dramatically due to climate change — summer sea ice extent has declined by about 40% since satellite records began in 1979. The Arctic is warming approximately four times faster than the global average.", category: "nature" },
  { question: "Where is Fiordland?", answer: "Southland, New Zealand", lat: -45.4149, lng: 167.7196, info: "New Zealand's largest national park at 1.26 million hectares is home to Milford Sound and Doubtful Sound, carved by glaciers over millions of years into sheer cliffs rising over 1,200 metres from the sea. Receiving up to 8 metres of rain annually, Fiordland is one of the wettest places on Earth and supports ancient temperate rainforest reaching to the water's edge.", category: "nature" },
  { question: "Where is Mount Erebus?", answer: "Ross Island, Antarctica", lat: -77.5317, lng: 167.1533, info: "At 3,794 metres, Mount Erebus is the southernmost active volcano on Earth and the highest peak in Antarctica, containing one of the world's few permanent lava lakes in its crater. Discovered by James Clark Ross in 1841, it is named after one of his ships and its constant volcanic activity has been continuously monitored since the 1970s.", category: "nature" },
];
